2581     int getLookAheadScore(Value *LHS, Value *RHS, ArrayRef<Value *> MainAltOps,
2582                           int Lane, unsigned OpIdx, unsigned Idx,
2583                           bool &IsUsed, const SmallBitVector &UsedLanes) {
2584       LookAheadHeuristics LookAhead(TLI, DL, SE, R, getNumLanes(),
