2858              "Expected same number of lanes");
2859       assert(S.valid() && "InstructionsState is invalid.");
2860       // IntrinsicInst::isCommutative returns true if swapping the first "two"
2861       // arguments to the intrinsic produces the same result.
2862       constexpr unsigned IntrinsicNumOperands = 2;
2863       Instruction *MainOp = S.getMainOp();
2864       unsigned NumOperands = MainOp->getNumOperands();
2865       ArgSize = isa<IntrinsicInst>(MainOp) ? IntrinsicNumOperands : NumOperands;
2866       OpsVec.resize(NumOperands);
2867       unsigned NumLanes = VL.size();
2868       for (OperandDataVec &Ops : OpsVec)
2869         Ops.resize(NumLanes);
2870       for (unsigned Lane : seq<unsigned>(NumLanes)) {
2871         Value *V = VL[Lane];
2872         assert((isa<Instruction>(V) || isa<PoisonValue>(V)) &&
2873                "Expected instruction or poison value");
2874         if (isa<PoisonValue>(V)) {
2875           for (unsigned OpIdx : seq<unsigned>(NumOperands))
2876             OpsVec[OpIdx][Lane] = {
2877                 PoisonValue::get(MainOp->getOperand(OpIdx)->getType()), true,
2878                 false};
2879           if (auto *EI = dyn_cast<ExtractElementInst>(MainOp)) {
2880             OpsVec[0][Lane] = {EI->getVectorOperand(), true, false};
2881           } else if (auto *EV = dyn_cast<ExtractValueInst>(MainOp)) {
2882             OpsVec[0][Lane] = {EV->getAggregateOperand(), true, false};
2883           }
2884           continue;
2885         }
2886         // Our tree has just 3 nodes: the root and two operands.
2887         // It is therefore trivial to get the APO. We only need to check the
2888         // opcode of V and whether the operand at OpIdx is the LHS or RHS
2889         // operand. The LHS operand of both add and sub is never attached to an
2890         // inversese operation in the linearized form, therefore its APO is
2891         // false. The RHS is true only if V is an inverse operation.
2892 
2893         // Since operand reordering is performed on groups of commutative
2894         // operations or alternating sequences (e.g., +, -), we can safely tell
2895         // the inverse operations by checking commutativity.
2896         auto [SelectedOp, Ops] = convertTo(cast<Instruction>(VL[Lane]), S);
