1655 /// Checks if the provided value does not require scheduling. It does not
1656 /// require scheduling if this is not an instruction or it is an instruction
1657 /// that does not read/write memory and all operands are either not instructions
1658 /// or phi nodes or instructions from different blocks.
1659 static bool areAllOperandsNonInsts(Value *V) {
1660   auto *I = dyn_cast<Instruction>(V);
