1672 /// Checks if the provided value does not require scheduling. It does not
1673 /// require scheduling if this is not an instruction or it is an instruction
1674 /// that does not read/write memory and all users are phi nodes or instructions
1675 /// from the different blocks.
1676 static bool isUsedOutsideBlock(Value *V) {
1677   auto *I = dyn_cast<Instruction>(V);
1678   if (!I)
1679     return true;
1680   // Limits the number of uses to save compile time.
1681   return !I->mayReadOrWriteMemory() && !I->hasNUsesOrMore(UsesLimit) &&
1682          all_of(I->users(), [I](User *U) {
1683            auto *IU = dyn_cast<Instruction>(U);
1684            if (!IU)
1685              return true;
1686            return IU->getParent() != I->getParent() || isa<PHINode>(IU);
1687          });
