1691 /// require scheduling if all operands and all users do not need to be scheduled
1692 /// in the current basic block.
1693 static bool doesNotNeedToBeScheduled(Value *V) {
1694   return areAllOperandsNonInsts(V) && isUsedOutsideBlock(V);
