1697 /// Checks if the specified array of instructions does not require scheduling.
1698 /// It is so if all either instructions have operands that do not require
1699 /// scheduling or their users do not require scheduling since they are phis or
1700 /// in other basic blocks.
1701 static bool doesNotNeedToSchedule(ArrayRef<Value *> VL) {
1702   return !VL.empty() &&
1703          (all_of(VL, isUsedOutsideBlock) || all_of(VL, areAllOperandsNonInsts));
